    print("="*60 + "\n")

    # 3. Loop de Tradução e Avaliação
    for i, (paragrafo_it, paragrafo_ref) in enumerate(zip(noticia_italiano, referencia_gemini)):

        # O modelo pode falhar com textos muito grandes, vamos truncar se necessário
        encoded_it = tokenizer(paragrafo_it, return_tensors="pt", truncation=True, max_length=512)
        generated_tokens = model.generate(**encoded_it, forced_bos_token_id=id_destino)
        traducao_mbart = tokenizer.batch_decode(generated_tokens, skip_special_tokens=True)[0]

        # Avaliação
        bleu = sacrebleu.sentence_bleu(traducao_mbart, [paragrafo_ref])
        notas_bleu.append(bleu.score)
        paragrafos_numeros.append(f"P{i+1}")

        print(f"Parágrafo {i+1} | BLEU: {bleu.score:.2f}")

    # Média Métrica Final
    media = sum(notas_bleu) / len(notas_bleu)
    print(f"\n🎯 Média BLEU (mBART): {media:.2f} / 100.00")

    # ==========================================
    # 4. GERANDO O GRÁFICO COM MATPLOTLIB
    # ==========================================
    print("\nGerando gráfico de desempenho...")

